package com.aadil.jobtracker.exceptions;import org.jetbrains.annotations.NotNull;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.MethodArgumentNotValidException;import org.springframework.web.bind.annotation.ExceptionHandler;import org.springframework.web.bind.annotation.RestControllerAdvice;import java.time.LocalDateTime;import java.util.HashMap;import java.util.Map;@RestControllerAdvicepublic class GlobalExceptionHandler {    @ExceptionHandler(BadRequestException.class)    public ResponseEntity<@NotNull ErrorResponse> handlesBadRequests(BadRequestException badRequestException){        ErrorResponse errorResponse=new ErrorResponse(badRequestException.getMessage(), HttpStatus.BAD_REQUEST.value(), LocalDateTime.now());        return new ResponseEntity<>(errorResponse,HttpStatus.BAD_REQUEST);    }    @ExceptionHandler(ResourceNotFoundException.class)    public ResponseEntity<@NotNull ErrorResponse> handlesNotFound(ResourceNotFoundException notFoundException){        ErrorResponse errorResponse=new ErrorResponse(notFoundException.getMessage(), HttpStatus.NOT_FOUND.value(), LocalDateTime.now());        return new ResponseEntity<>(errorResponse,HttpStatus.NOT_FOUND);    }    @ExceptionHandler(RuntimeException.class)    public  ResponseEntity<@NotNull ErrorResponse> handlesAll(RuntimeException exception){        ErrorResponse errorResponse=new ErrorResponse("Something went wrong", HttpStatus.INTERNAL_SERVER_ERROR.value(), LocalDateTime.now());        return new ResponseEntity<>(errorResponse,HttpStatus.INTERNAL_SERVER_ERROR);    }    @ExceptionHandler(MethodArgumentNotValidException.class)    public ResponseEntity<@NotNull Map<String,String>> handlesMethodArgument(MethodArgumentNotValidException argumentNotValidException){        Map<String,String> errors=new HashMap<>();        argumentNotValidException.getBindingResult().getFieldErrors().forEach(fieldError ->                errors.put(fieldError.getField(), fieldError.getDefaultMessage()));        return new ResponseEntity<>(errors,HttpStatus.BAD_REQUEST);    }}